    .replace(/<[^>]+>/g, ' ')
    .replace(/ /g, ' ')
    .replace(//g, '')
    .trim();
}

function extractNameFromSignature(body) {
  const plainBody = stripHtml(body);
  const lines = plainBody.split('
').map((line) => line.trim()).filter(Boolean);
  const closings =
    /^(mit (freundlichen )?grüßen|freundliche grüße|best regards|kind regards|many thanks|thanks|thank you|viele grüße|liebe grüße|herzliche grüße|lg|grüße|mfg|regards|cheers)$/i;

  for (let i = lines.length - 1; i >= 0; i -= 1) {
    if (!closings.test(lines[i])) continue;
    for (let j = i + 1; j < Math.min(i + 4, lines.length); j += 1) {
      const candidate = normalizeCreatorName(lines[j]);
      if (candidate && isLikelyPersonName(lines[j])) return candidate;
    }
  }

  for (let i = lines.length - 1; i >= Math.max(0, lines.length - 5); i -= 1) {
    const candidate = normalizeCreatorName(lines[i]);
    if (candidate && isLikelyPersonName(lines[i])) return candidate;
  }

  return '';
}

const creatorName =
  normalizeCreatorName(parsed.creatorName) ||
  extractNameFromSignature(email.body) ||
  parseFromDisplayName(fromRaw) ||
  '';

return [
  {
    json: {
      title: String(parsed.title || email.subject || 'Stakeholder request').trim(),
      description: String(parsed.description || email.body || '').trim(),
      category: validCategories.has(parsed.category) ? parsed.category : 'User Story',
      priority: validPriorities.has(parsed.priority) ? parsed.priority : 'MidPriority',
      dueDate: typeof parsed.dueDate === 'string' ? parsed.dueDate.trim() : '',
      column: 'triageColumn',
      creatorName,
      creatorEmail,
      creatorType: 'external',
      aiGenerated: true,
    },
  },
];
